# approval_gate.py — minimal approval gate implementation
from dataclasses import dataclass, field
from enum import Enum
from typing import Any, Callable
import logging

logger = logging.getLogger(__name__)


class Decision(str, Enum):
    ALLOW = "allow"
    HOLD = "hold"
    DENY = "deny"


@dataclass
class ActionRequest:
    tool_name: str
    arguments: dict[str, Any]
    task_id: str
    user_id: str
    environment: str = "production"


@dataclass
class GateDecision:
    decision: Decision
    policy_id: str
    reason: str
    modified_arguments: dict[str, Any] | None = None


class PolicyEngine:
    """Evaluate action requests against a list of policy rules."""

    def __init__(self, rules: list[dict]):
        # rules: [{match: {tool_name: ..., ...}, decision: ..., reason: ...}]
        self.rules = rules

    def evaluate(self, action: ActionRequest) -> GateDecision:
        for rule in self.rules:
            if self._matches(rule["match"], action):
                return GateDecision(
                    decision=Decision(rule["decision"]),
                    policy_id=rule["id"],
                    reason=rule["reason"],
                )
        # Default allow if no rule matches
        return GateDecision(decision=Decision.ALLOW, policy_id="default", reason="No matching deny/hold rule")

    def _matches(self, match: dict, action: ActionRequest) -> bool:
        if "tool_name" in match and match["tool_name"] != action.tool_name:
            return False
        if "environment" in match and match["environment"] != action.environment:
            return False
        if "user_id" in match and match["user_id"] != action.user_id:
            return False
        return True


class ApprovalGate:
    def __init__(self, policy_engine: PolicyEngine, hold_queue):
        self.policy_engine = policy_engine
        self.hold_queue = hold_queue

    def intercept(self, action: ActionRequest, execute_fn: Callable) -> Any:
        """Intercept an action, evaluate, and execute or block."""
        gate_decision = self.policy_engine.evaluate(action)
        logger.info(
            "gate_decision",
            extra={"action": action, "decision": gate_decision.decision, "policy": gate_decision.policy_id},
        )

        if gate_decision.decision == Decision.DENY:
            raise PermissionError(f"Action denied by policy {gate_decision.policy_id}: {gate_decision.reason}")

        if gate_decision.decision == Decision.HOLD:
            pending_id = self.hold_queue.enqueue(action, gate_decision)
            # Suspend here — in a real system this would await an async event
            approved, modified = self.hold_queue.wait_for_decision(pending_id)
            if not approved:
                raise PermissionError(f"Human reviewer denied action: {gate_decision.reason}")
            if modified:
                action.arguments.update(modified)

        # ALLOW (or approved after HOLD) — execute the action
        return execute_fn(action.arguments)
